import { useState, useEffect, useMemo } from "react";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Label } from "../components/ui/label";
import { Textarea } from "../components/ui/textarea";
import { Briefcase, Save } from "lucide-react";
import { toast } from "sonner";

export default function ProfilPerusahaan() {
  const { company, setCompany } = useData();

  const [form, setForm] = useState({
    name: "",
    legalName: "",
    email: "",
    phone: "",
    website: "",
    taxId: "",
    address: "",
    description: "",
    employees: "",
    founded: "",
    branches: ""
  });

  const [loading, setLoading] = useState(false);

  // Sync data dari context
  useEffect(() => {
    if (company) {
      setForm({
        name: company.name || "",
        legalName: company.legalName || "",
        email: company.email || "",
        phone: company.phone || "",
        website: company.website || "",
        taxId: company.taxId || "",
        address: company.address || "",
        description: company.description || "",
        employees: company.employees || "",
        founded: company.founded || "",
        branches: company.branches || ""
      });
    }
  }, [company]);

  // Detect perubahan
  const isChanged = useMemo(() => {
    return JSON.stringify(form) !== JSON.stringify(company);
  }, [form, company]);

  // Handle input change
  const handleChange = (key, value) => {
    setForm(prev => ({
      ...prev,
      [key]: value
    }));
  };

  // Validasi sederhana
  const validate = () => {
    if (!form.name) return "Nama perusahaan wajib diisi";
    if (!form.email) return "Email wajib diisi";
    return null;
  };

  // Save handler
  const handleSave = async () => {
    const error = validate();
    if (error) {
      toast.error(error);
      return;
    }

    try {
      setLoading(true);

      // Simulasi async (kalau nanti pakai API)
      await new Promise(resolve => setTimeout(resolve, 500));

      setCompany(form);
      toast.success("Profil perusahaan berhasil diperbarui");
    } catch (err) {
      toast.error("Gagal menyimpan data");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-[1100px]" data-testid="profil-perusahaan-page">
      <h1 className="text-3xl font-extrabold text-gray-900">
        Profil Perusahaan
      </h1>
      <p className="text-sm text-gray-500 mt-1 mb-8">
        Informasi resmi perusahaan dan dokumentasi
      </p>

      <div className="grid grid-cols-1 lg:grid-cols-[1fr_2fr] gap-6">
        {/* LEFT */}
        <div className="mpl-card p-7 h-fit">
          <div className="w-24 h-24 rounded-2xl bg-[#1a1a1a] flex items-center justify-center mb-5 mx-auto">
            <span className="text-[#F59E0B] font-extrabold text-3xl">
              {form.name?.slice(0, 3).toUpperCase() || "CMP"}
            </span>
          </div>

          <div className="text-center">
            <div className="text-lg font-bold text-gray-900">
              {form.name || "-"}
            </div>
            <div className="text-xs text-gray-500 mt-1">
              Berdiri sejak {form.founded || "-"}
            </div>
          </div>

          <div className="mt-6 pt-6 border-t border-gray-100 space-y-3 text-sm">
            <Stat label="Karyawan" value={form.employees || "-"} />
            <Stat label="NPWP" value={form.taxId || "-"} />
            <Stat label="Cabang" value={form.branches || "-"} />
          </div>
        </div>

        {/* RIGHT */}
        <div className="mpl-card p-7">
          <div className="flex items-center gap-2 mb-6">
            <Briefcase className="w-4 h-4 text-[#F59E0B]" />
            <h3 className="text-lg font-bold text-gray-900">
              Detail Perusahaan
            </h3>
          </div>

          <div className="grid grid-cols-2 gap-5">
            <FormField label="Nama Perusahaan">
              <Input
                value={form.name}
                onChange={(e) => handleChange("name", e.target.value)}
              />
            </FormField>

            <FormField label="Nama Legal">
              <Input
                value={form.legalName}
                onChange={(e) =>
                  handleChange("legalName", e.target.value)
                }
              />
            </FormField>

            <FormField label="Email">
              <Input
                type="email"
                value={form.email}
                onChange={(e) => handleChange("email", e.target.value)}
              />
            </FormField>

            <FormField label="Telepon">
              <Input
                value={form.phone}
                onChange={(e) => handleChange("phone", e.target.value)}
              />
            </FormField>

            <FormField label="Website">
              <Input
                value={form.website}
                onChange={(e) => handleChange("website", e.target.value)}
              />
            </FormField>

            <FormField label="NPWP">
              <Input
                value={form.taxId}
                onChange={(e) => handleChange("taxId", e.target.value)}
              />
            </FormField>

            <FormField label="Jumlah Karyawan">
              <Input
                value={form.employees}
                onChange={(e) =>
                  handleChange("employees", e.target.value)
                }
              />
            </FormField>

            <FormField label="Tahun Berdiri">
              <Input
                value={form.founded}
                onChange={(e) =>
                  handleChange("founded", e.target.value)
                }
              />
            </FormField>

            <FormField label="Jumlah Cabang">
              <Input
                value={form.branches}
                onChange={(e) =>
                  handleChange("branches", e.target.value)
                }
              />
            </FormField>

            <div className="col-span-2">
              <FormField label="Alamat">
                <Input
                  value={form.address}
                  onChange={(e) =>
                    handleChange("address", e.target.value)
                  }
                />
              </FormField>
            </div>

            <div className="col-span-2">
              <FormField label="Deskripsi">
                <Textarea
                  rows={4}
                  value={form.description}
                  onChange={(e) =>
                    handleChange("description", e.target.value)
                  }
                />
              </FormField>
            </div>
          </div>

          <div className="mt-6 flex justify-end">
            <Button
              onClick={handleSave}
              disabled={!isChanged || loading}
              className="mpl-btn-primary h-11 px-6"
            >
              <Save className="w-4 h-4 mr-2" />
              {loading ? "Menyimpan..." : "Simpan Perubahan"}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ===== COMPONENT KECIL =====
function Stat({ label, value }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-xs uppercase tracking-wider text-gray-400 font-semibold">
        {label}
      </span>
      <span className="text-sm font-semibold text-gray-900">
        {value}
      </span>
    </div>
  );
}

function FormField({ label, children }) {
  return (
    <div>
      <Label className="text-[10px] tracking-wider uppercase text-gray-500 font-semibold">
        {label}
      </Label>
      <div className="mt-1.5">{children}</div>
    </div>
  );
}
